sql:
SELECT analytic_type, AVG(confidence_level) AS average_confidence_level
FROM analytics_results
GROUP BY analytic_type;

SELECT frame_id, avg_brightness 
FROM frames 
WHERE avg_brightness > (SELECT AVG(avg_brightness) FROM frames);

SELECT *
FROM frames
WHERE brightness > 50;

SELECT AVG(CAST(SUBSTR(resolution, 1, INSTR(resolution, 'x') - 1) AS INTEGER) * 
           CAST(SUBSTR(resolution, INSTR(resolution, 'x') + 1) AS INTEGER)) AS AverageResolution
FROM frames;

SELECT video_name
FROM videos
WHERE video_id = 1;

SELECT camera_id, camera_name, camera_type, resolution, location
FROM cameras
WHERE camera_name LIKE '%Camera_002%';

SELECT COUNT(*) 
FROM notifications 
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT frame_id, brightness 
FROM frames 
WHERE brightness = (SELECT MAX(brightness) FROM frames);

external_knowledge:
- 'voyagers' refers to users;
- 'navigating through the stormy seas' symbolizes accessing videos;
- 'significant turbulence' is represented by 'high' and 'medium' alert levels;
- 'maritime charts' symbolize the analytics_results, which track alert levels for video frames.
